""" Dashboard and Booking Pages Handles navigation and booking selection """
from pages.base_page import BasePage from playwright.sync_api import Page import logging
logger = logging.getLogger(__name__)
class DashboardPage(BasePage): """Page object for the dashboard"""
# Locators - flexible selector to handle Vue.js and whitespace BOOK_A_SCAN_BUTTON = '[data-testid="book-scan-btn"]'
def __init__(self, page: Page, wait_timeout: int = 15000): super().__init__(page, wait_timeout) logger.info("DashboardPage initialized")
def is_dashboard_displayed(self) -> bool: """Verify that the dashboard is displayed - polls for element""" import time logger.info("Polling for dashboard (max 30 seconds)") start_time = time.time()
while time.time() - start_time < 30: if self.is_element_visible(self.BOOK_A_SCAN_BUTTON): elapsed = time.time() - start_time logger.info(f"Dashboard found in {elapsed:.1f}s") return True time.sleep(1) # Check every 1 second
logger.warning("Dashboard not found within 30 seconds") return False
def click_book_a_scan(self): """Click the 'Book a Scan' button""" logger.info("Clicking 'Book a Scan' button") self.click(self.BOOK_A_SCAN_BUTTON) self.wait_for_navigation() logger.info("Successfully clicked 'Book a Scan' and navigated")
class ScanSelectionPage(BasePage): """Page object for scan type selection"""
# Locators MRI_SCAN_CARD = ':has-text("MRI Scan")' CONTINUE_BUTTON = 'button:has-text("Continue"), [role="button"]:has-text("Continue")'
def __init__(self, page: Page, wait_timeout: int = 15000): super().__init__(page, wait_timeout) logger.info("ScanSelectionPage initialized")
def is_scan_selection_displayed(self) -> bool: """Verify that scan selection page is displayed - polls for element""" import time logger.info("Polling for scan selection (max 30 seconds)") start_time = time.time()
while time.time() - start_time < 30: if self.is_element_visible(self.MRI_SCAN_CARD): elapsed = time.time() - start_time logger.info(f"Scan selection found in {elapsed:.1f}s") return True time.sleep(1) # Check every 1 second
logger.warning("Scan selection not found within 30 seconds") return False
def select_mri_scan(self): """Select the MRI Scan option""" logger.info("Selecting MRI Scan") self.click(self.MRI_SCAN_CARD) logger.info("MRI Scan selected")
def click_continue(self): """Click the Continue button""" logger.info("Clicking Continue button for scan selection") self.click_when_enabled(self.CONTINUE_BUTTON) self.wait_for_navigation() logger.info("Navigation completed after scan selection")
class LocationSelectionPage(BasePage): """Page object for location selection"""
# Locators RECOMMENDED_LOCATION = ':has-text("Recommended")' LOCATION_CARD = '[role="button"], .location-card'
def __init__(self, page: Page, wait_timeout: int = 15000): super().__init__(page, wait_timeout) logger.info("LocationSelectionPage initialized")
def is_location_selection_displayed(self) -> bool: """Verify that location selection page is displayed - polls for element""" import time logger.info("Polling for location selection (max 30 seconds)") start_time = time.time()
while time.time() - start_time < 30: if self.is_element_visible(self.RECOMMENDED_LOCATION): elapsed = time.time() - start_time logger.info(f"Location selection found in {elapsed:.1f}s") return True time.sleep(1) # Check every 1 second
logger.warning("Location selection not found within 30 seconds") return False
def select_recommended_location(self): """Click on the recommended location""" logger.info("Selecting recommended location")
# Find the element with "Recommended" text if self.is_element_visible(self.RECOMMENDED_LOCATION): self.click(self.RECOMMENDED_LOCATION) logger.info("Recommended location clicked") import time time.sleep(1) else: raise Exception("Recommended location not found")
def get_recommended_address(self) -> str: """Get the address of the recommended location""" address_text = self.get_text(self.RECOMMENDED_LOCATION) logger.info(f"Recommended address: {address_text}") return address_text

""" Dashboard and Booking Pages Handles navigation and booking selection """
from pages.base_page import BasePage from playwright.sync_api import Page import logging
logger = logging.getLogger(__name__)
class DashboardPage(BasePage): """Page object for the dashboard"""
# Locators - flexible selector to handle Vue.js and whitespace BOOK_A_SCAN_BUTTON = '[data-testid="book-scan-btn"]'
def __init__(self, page: Page, wait_timeout: int = 15000): super().__init__(page, wait_timeout) logger.info("DashboardPage initialized")
def is_dashboard_displayed(self) -> bool: """Verify that the dashboard is displayed - polls for button visibility""" import time logger.info("Polling for dashboard button (max 30 seconds)") start_time = time.time()
while time.time() - start_time < 30: try: button = self.page.locator(self.BOOK_A_SCAN_BUTTON) if button.count() > 0: # Check if button is visible AND enabled if button.first.is_visible() and button.first.is_enabled(): elapsed = time.time() - start_time logger.info(f"Dashboard button found and visible in {elapsed:.1f}s") return True else: logger.debug(f"Button found but not visible/enabled yet") except Exception as e: logger.debug(f"Error checking button: {e}")
time.sleep(1) # Check every 1 second
logger.warning("Dashboard button not found or not visible within 30 seconds") return False
def click_book_a_scan(self): """Click the 'Book a Scan' button""" logger.info("Clicking 'Book a Scan' button") self.click(self.BOOK_A_SCAN_BUTTON) self.wait_for_navigation() logger.info("Successfully clicked 'Book a Scan' and navigated")
